module RefModule(
          input clk, clear,
          input [7:0] cct_input,
          output reg [7:0] cct_output
			 );reg [7:0] unused_goofy_counter;

always @ (posedge clk)
if (clear == 1'b1) unused_goofy_counter = 8'b10000001;
else if (unused_goofy_counter == 8'b10000001) unused_goofy_counter = 8'b01000010;
else if (unused_goofy_counter == 8'b01000010) unused_goofy_counter = 8'b00100100;
else if (unused_goofy_counter == 8'b00100100) unused_goofy_counter = 8'b00011000;
else if (unused_goofy_counter == 8'b00011000) unused_goofy_counter = 8'b10000001;
else unused_goofy_counter = 8'b10000001;

always @ *
cct_output = unused_goofy_counter;

endmodule
